//! Disk-backed cache of pooled tool-description embeddings, keyed by a
//! content hash of `name + description` (so any description edit is a cache
//! miss, not stale data). Mirrors `prompt_cache.rs`'s own reasoning: moonshine
//! runs as a fresh process per `-c` invocation, so an in-memory map would
//! never survive to the next call — this has to be on disk to help at all.
//!
//! Unlike `prompt_cache.rs`'s one-file-per-entry layout, this is a single
//! flat append-only binary file: `N` here is the size of the tool catalog
//! (thousands), and opening one file per entry on every session start would
//! be real overhead a single sequential read avoids.
//!
//! Record layout, repeated to EOF: `[u64 key LE][u32 dim LE][dim x f32 LE]`.

use std::fs::{File, OpenOptions};
use std::io::{BufReader, Read, Write};
use std::path::PathBuf;

const FNV_OFFSET: u64 = 0xcbf2_9ce4_8422_2325;
const FNV_PRIME: u64 = 0x0000_0100_0000_01b3;

fn fnv1a64(bytes: &[u8]) -> u64 {
    let mut h = FNV_OFFSET;
    for &b in bytes {
        h ^= b as u64;
        h = h.wrapping_mul(FNV_PRIME);
    }
    h
}

/// Content-hash key for a tool's `(name, description)` pair — any edit to
/// either changes the key, so a stale cached vector is simply never looked
/// up again rather than needing explicit invalidation.
pub(crate) fn content_key(name: &str, description: &str) -> u64 {
    let mut bytes = Vec::with_capacity(name.len() + description.len() + 1);
    bytes.extend_from_slice(name.as_bytes());
    bytes.push(0x1f); // unit separator: cheap, unambiguous field join
    bytes.extend_from_slice(description.as_bytes());
    fnv1a64(&bytes)
}

/// On unless `MOONSHINE_NO_SEMANTIC_TOOLS` is set — the single opt-out for
/// the whole semantic-scoring feature (cache included).
pub(crate) fn enabled() -> bool {
    std::env::var("MOONSHINE_NO_SEMANTIC_TOOLS").is_err()
}

/// `MOONSHINE_CACHE_DIR`, else `$XDG_CACHE_HOME/moonshine/tool-embeddings`,
/// else `$HOME/.cache/...`, else a temp dir — same resolution order as
/// `prompt_cache::cache_dir()`.
fn cache_dir() -> PathBuf {
    if let Ok(d) = std::env::var("MOONSHINE_CACHE_DIR") {
        return PathBuf::from(d);
    }
    let base = std::env::var("XDG_CACHE_HOME")
        .map(PathBuf::from)
        .or_else(|_| std::env::var("HOME").map(|h| PathBuf::from(h).join(".cache")))
        .unwrap_or_else(|_| std::env::temp_dir());
    base.join("moonshine").join("tool-embeddings")
}

fn cache_path() -> PathBuf {
    cache_dir().join("index.bin")
}

pub(crate) struct ToolEmbedCache {
    entries: std::collections::HashMap<u64, Vec<f32>>,
}

impl ToolEmbedCache {
    /// Never fatal — a missing or corrupt cache file just starts empty
    /// rather than blocking the turn loop on a cache-format problem.
    pub(crate) fn load() -> Self {
        let mut entries = std::collections::HashMap::new();
        if !enabled() {
            return Self { entries };
        }
        let Ok(file) = File::open(cache_path()) else {
            return Self { entries };
        };
        let mut reader = BufReader::new(file);
        loop {
            let mut key_buf = [0u8; 8];
            if reader.read_exact(&mut key_buf).is_err() {
                break;
            }
            let key = u64::from_le_bytes(key_buf);
            let mut dim_buf = [0u8; 4];
            if reader.read_exact(&mut dim_buf).is_err() {
                break;
            }
            let dim = u32::from_le_bytes(dim_buf) as usize;
            let mut vec_buf = vec![0u8; dim * 4];
            if reader.read_exact(&mut vec_buf).is_err() {
                break;
            }
            let vector: Vec<f32> = vec_buf
                .chunks_exact(4)
                .map(|c| f32::from_le_bytes([c[0], c[1], c[2], c[3]]))
                .collect();
            entries.insert(key, vector);
        }
        Self { entries }
    }

    pub(crate) fn get(&self, key: u64) -> Option<&[f32]> {
        self.entries.get(&key).map(|v| v.as_slice())
    }

    /// Appends one record to disk (best-effort — a write failure is logged
    /// and otherwise ignored, since the in-memory entry still serves the
    /// rest of this session) and updates the in-memory map.
    pub(crate) fn insert_and_persist(&mut self, key: u64, vector: Vec<f32>) {
        if enabled() {
            if let Err(error) = self.append_to_disk(key, &vector) {
                eprintln!("[semantic-tools] failed to persist tool embedding: {error}");
            }
        }
        self.entries.insert(key, vector);
    }

    fn append_to_disk(&self, key: u64, vector: &[f32]) -> std::io::Result<()> {
        let path = cache_path();
        if let Some(parent) = path.parent() {
            std::fs::create_dir_all(parent)?;
        }
        let mut file = OpenOptions::new().create(true).append(true).open(path)?;
        file.write_all(&key.to_le_bytes())?;
        file.write_all(&(vector.len() as u32).to_le_bytes())?;
        for value in vector {
            file.write_all(&value.to_le_bytes())?;
        }
        Ok(())
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn content_key_changes_when_description_changes() {
        let a = content_key("local/list_directory", "list files");
        let b = content_key("local/list_directory", "list files and directories");
        assert_ne!(a, b);
    }

    #[test]
    fn content_key_is_stable_for_the_same_input() {
        let a = content_key("local/list_directory", "list files");
        let b = content_key("local/list_directory", "list files");
        assert_eq!(a, b);
    }

    #[test]
    fn roundtrip_via_temp_dir() {
        let dir = std::env::temp_dir().join(format!(
            "moonshine-tool-embed-cache-test-{}",
            std::process::id()
        ));
        // SAFETY: test-only env mutation, scoped to this process; no other
        // test in this binary reads MOONSHINE_CACHE_DIR concurrently within
        // the same process (cargo test runs each test in its own thread but
        // env vars are process-global — accepted here, mirrors the existing
        // `prompt_cache::tests::roundtrip_via_temp_dir` pattern).
        unsafe {
            std::env::set_var("MOONSHINE_CACHE_DIR", &dir);
        }
        let key = content_key("aic/delegation_verify", "verify a delegation chain");
        let mut cache = ToolEmbedCache::load();
        assert!(cache.get(key).is_none());
        cache.insert_and_persist(key, vec![0.1, 0.2, 0.3]);
        assert_eq!(cache.get(key), Some([0.1f32, 0.2, 0.3].as_slice()));

        let reloaded = ToolEmbedCache::load();
        assert_eq!(reloaded.get(key), Some([0.1f32, 0.2, 0.3].as_slice()));

        unsafe {
            std::env::remove_var("MOONSHINE_CACHE_DIR");
        }
        let _ = std::fs::remove_dir_all(&dir);
    }
}
